module shift_register (
        input clk,
        input load,
        input shift,
        input rst,
        input [7:0] pdata,
        output reg [7:0] q);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge rst or posedge dbg_halt) begin
        if (rst)
            q <= 8'b00000000;
        else if (load)
            q <= pdata;
        else if (shift)
            q <= {q[6:0], 1'b0};
    end

endmodule
